@page "/privacy"
@using Microsoft.AspNetCore.Http
@attribute [ExcludeFromInteractiveRouting]

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This site uses cookies to improve your experience.
    We collect only the data necessary to operate and enhance our services.
</p>

@if (HasConsented)
{
    <div class="alert alert-success mt-3">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning mt-3">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

@code {
    private bool HasConsented { get; set; }

    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    protected override void OnInitialized()
    {
        HasConsented = HttpContext?.Request.Cookies.ContainsKey("consent") is true;
    }
}

